export default class Router{constructor(){this.routes={},this.errorCallback=null,this.activeController=null}get(t,r){this.routes[t]=r}error(t){this.errorCallback=t}async resolve(t=null){const r=window.location.pathname||"/",o=t||r;console.log(`Router: Attempting to resolve [${o}]`);const e=this.routes[o];this.activeController?.destroy&&this.activeController.destroy(),e?this.activeController=await e():this.errorCallback&&(this.activeController=await this.errorCallback())}}